type BlockerReportSummary = {
  total: number
  passed: number
  failed: number
  durationMs: number
}

function waitMs(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

function classifyFailureDomain(endpoint: string | null, stepKey: string): string {
  if (endpoint) {
    if (endpoint.includes('/enterprise/')) return 'enterprise'
    if (endpoint.includes('/sales-quote')) return 'sales_quotes'
    if (endpoint.includes('/wishlist')) return 'wishlists'
    if (endpoint.includes('/leave-')) return 'leave'
    if (endpoint.includes('/access-security') || endpoint.includes('/public/access/')) {
      return 'access_security'
    }
    if (endpoint.includes('/installment-')) return 'installments'
    if (endpoint.includes('/payment')) return 'payments'
    if (endpoint.includes('/communications') || endpoint.includes('/messages')) {
      return 'communications'
    }
  }
  if (stepKey.startsWith('uc-need-validate')) return 'validator'
  return 'general'
}

function parseFailureRecord(run: FailedRunRecord, failure: string): FailureRecord {
  const [rawStepKey, ...messageParts] = failure.split(': ')
  const stepKey = rawStepKey || 'unknown-step'
  const message = messageParts.join(': ') || failure
  const httpMatch = message.match(/HTTP (\d{3}) for ([A-Z]+) ([^:]+):/)
  const endpoint = httpMatch?.[3] ?? null
  const statusCode = httpMatch ? Number(httpMatch[1]) : null

  let kind = 'runtime'
  if (message.includes('VALIDATION_ERROR')) kind = 'validation_error'
  else if (message.includes('violates foreign key constraint')) kind = 'foreign_key'
  else if (message.includes('Runner executor is not implemented')) kind = 'runner_gap'
  else if (message.includes('Step contract failed')) kind = 'contract_gap'
  else if (message.includes('Exploratory validation failed')) kind = 'exploratory_gap'
  else if (httpMatch) kind = `http_${statusCode}`

  const domain = classifyFailureDomain(endpoint, stepKey)
  const signature = [domain, kind, endpoint ?? 'no-endpoint', stepKey].join('|')

  return {
    sagaKey: run.sagaKey,
    runId: run.runId,
    stepKey,
    message,
    kind,
    endpoint,
    statusCode,
    domain,
    signature,
  }
}

async function writeBlockerReport(failedRuns: FailedRunRecord[], summary: BlockerReportSummary) {
  const failureRecords = failedRuns.flatMap((run) =>
    run.failures.map((failure) => parseFailureRecord(run, failure)),
  )

  const grouped = new Map<string, BlockerGroup>()
  for (const failure of failureRecords) {
    const existing = grouped.get(failure.signature)
    if (existing) {
      existing.count += 1
      if (!existing.sagaKeys.includes(failure.sagaKey)) existing.sagaKeys.push(failure.sagaKey)
      if (!existing.stepKeys.includes(failure.stepKey)) existing.stepKeys.push(failure.stepKey)
      if (existing.examples.length < 3) existing.examples.push(failure.message)
      continue
    }
    grouped.set(failure.signature, {
      key: failure.signature,
      domain: failure.domain,
      kind: failure.kind,
      endpoint: failure.endpoint,
      statusCode: failure.statusCode,
      count: 1,
      sagaKeys: [failure.sagaKey],
      stepKeys: [failure.stepKey],
      examples: [failure.message],
    })
  }

  const blockerGroups = Array.from(grouped.values()).sort((a, b) => b.count - a.count)
  const domainSummary = Array.from(
    blockerGroups.reduce(
      (map, group) => map.set(group.domain, (map.get(group.domain) ?? 0) + group.count),
      new Map<string, number>(),
    ),
  )
    .map(([domain, count]) => ({ domain, count }))
    .sort((a, b) => b.count - a.count)

  await mkdir(SAGA_REPORT_DIR, { recursive: true })
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-')
  const jsonPath = path.join(SAGA_REPORT_DIR, `blockers-${timestamp}.json`)
  const latestJsonPath = path.join(SAGA_REPORT_DIR, 'blockers-latest.json')
  const mdPath = path.join(SAGA_REPORT_DIR, `blockers-${timestamp}.md`)
  const latestMdPath = path.join(SAGA_REPORT_DIR, 'blockers-latest.md')

  const payload = {
    generatedAt: new Date().toISOString(),
    totalDefinitions: summary.total,
    processed: summary.total,
    passed: summary.passed,
    failed: summary.failed,
    durationMs: summary.durationMs,
    totalFailedRuns: failedRuns.length,
    totalFailures: failureRecords.length,
    domainSummary,
    blockerGroups,
    failureRecords,
  }

  const markdown = [
    '# Saga Blocker Report',
    '',
    `- generatedAt: \`${payload.generatedAt}\``,
    `- total: ${payload.totalDefinitions}`,
    `- passed: ${payload.passed}`,
    `- failed: ${payload.failed}`,
    `- durationMs: ${payload.durationMs}`,
    `- totalFailedRuns: ${payload.totalFailedRuns}`,
    `- totalFailures: ${payload.totalFailures}`,
    '',
    '## By Domain',
    ...(domainSummary.length > 0 ? domainSummary.map((row) => `- ${row.domain}: ${row.count}`) : ['- none']),
    '',
    '## Top Blockers',
    ...(blockerGroups.length > 0
      ? blockerGroups.slice(0, 50).flatMap((group) => [
          `### ${group.domain} | ${group.kind} | ${group.endpoint ?? 'no-endpoint'}`,
          `- count: ${group.count}`,
          `- sagas: ${group.sagaKeys.slice(0, 8).join(', ')}`,
          `- steps: ${group.stepKeys.join(', ')}`,
          ...group.examples.map((example) => `- example: ${example}`),
          '',
        ])
      : ['- none', '']),
  ].join('\n')

  await Promise.all([
    writeFile(jsonPath, JSON.stringify(payload, null, 2), 'utf8'),
    writeFile(latestJsonPath, JSON.stringify(payload, null, 2), 'utf8'),
    writeFile(mdPath, markdown, 'utf8'),
    writeFile(latestMdPath, markdown, 'utf8'),
  ])

  console.log('\nBlocker Report')
  console.log(`- json: ${latestJsonPath}`)
  console.log(`- md: ${latestMdPath}`)
}

function nowIso() {
  return new Date().toISOString()
}

function randomSuffix(length = 8) {
  return Math.random().toString(36).slice(2, 2 + length)
}

function toSlug(input: string, max = 80) {
  const cleaned = input
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-+/g, '-')
  return cleaned.slice(0, max).replace(/-+$/g, '')
}

function toTitleCase(input: string) {
  return input
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/\b\w/g, (ch) => ch.toUpperCase())
}

function prettyStepTitle(stepKey: string) {
  return toTitleCase(stepKey)
}

function asString(value: unknown) {
  if (value === null || value === undefined) return 'null'
  if (typeof value === 'string') return value
  if (typeof value === 'number' || typeof value === 'boolean') return String(value)
  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value) && typeof value === 'object' && !Array.isArray(value)
}

function traceValue(value: unknown): unknown {
  try {
    const text = JSON.stringify(value)
    if (!text) return value
    if (text.length <= 12000) return value
    return {
      _truncated: true,
      _preview: text.slice(0, 12000),
      _size: text.length,
    }
  } catch {
    return String(value)
  }
}

function cookieFromSetCookie(setCookieHeader: string | null): string {
  if (!setCookieHeader) {
    throw new Error('Missing Set-Cookie header from auth response.')
  }
  const tokenMatch = setCookieHeader.match(/better-auth\.session_token=[^;]+/)
  if (!tokenMatch) {
    throw new Error('Could not extract better-auth.session_token from Set-Cookie.')
  }
  return tokenMatch[0]
}

async function requestJson<T = unknown>(
  path: string,
  options: {
    method?: 'GET' | 'POST' | 'PATCH' | 'DELETE' | 'PUT'
    body?: unknown
    cookie?: string
    origin?: string
    authorization?: string
    apiKey?: string
    accessToken?: string
    bizIdHeader?: string
    acceptStatuses?: number[]
    raw?: boolean
  } = {},
): Promise<{ status: number; payload: T }> {
  const method = options.method ?? 'GET'
  const headers: Record<string, string> = {}
  if (options.body !== undefined) headers['content-type'] = 'application/json'
  if (options.cookie) headers.cookie = options.cookie
  if (options.origin) headers.origin = options.origin
  if (options.authorization) headers.authorization = options.authorization
  else if (options.accessToken) headers.authorization = `Bearer ${options.accessToken}`
  if (options.apiKey) headers['x-api-key'] = options.apiKey
  if (options.bizIdHeader) headers['x-biz-id'] = options.bizIdHeader

  const accepted = options.acceptStatuses ?? [200, 201]

  for (let attempt = 0; attempt <= HTTP_RETRY_COUNT; attempt += 1) {
    let response: Response
    let payload: T
    try {
      response = await fetch(`${API_BASE_URL}${path}`, {
        method,
        headers,
        body: options.body === undefined ? undefined : JSON.stringify(options.body),
        signal: AbortSignal.timeout(HTTP_TIMEOUT_MS),
      })
      payload = (await response.json().catch(() => null)) as T
    } catch (error) {
      const message =
        error instanceof Error && error.name === 'TimeoutError'
          ? `HTTP timeout after ${HTTP_TIMEOUT_MS}ms for ${method} ${path}`
          : error instanceof Error
            ? `${error.name}: ${error.message}`
            : String(error)
      if (attempt < HTTP_RETRY_COUNT) {
        await waitMs(HTTP_RETRY_BASE_DELAY_MS * (2 ** attempt))
        continue
      }
      throw new Error(message)
    }

    const activeApiTrace = stepTraceStore.getStore()
    if (activeApiTrace) {
      activeApiTrace.push({
        method,
        path,
        status: response.status,
        requestBody: options.body === undefined ? undefined : traceValue(options.body),
        responseBody: traceValue(payload),
        at: nowIso(),
      })
    }

    if (!accepted.includes(response.status)) {
      const retriableStatus = [429, 500, 502, 503, 504].includes(response.status)
      if (retriableStatus && attempt < HTTP_RETRY_COUNT) {
        await waitMs(HTTP_RETRY_BASE_DELAY_MS * (2 ** attempt))
        continue
      }
      throw new Error(`HTTP ${response.status} for ${method} ${path}: ${JSON.stringify(payload ?? {})}`)
    }

    if (!options.raw && payload && typeof payload === 'object' && 'success' in (payload as JsonObject)) {
      const asRecord = payload as JsonObject
      if (asRecord.success === false) {
        throw new Error(`API failure for ${method} ${path}: ${JSON.stringify(payload)}`)
      }
    }

    return { status: response.status, payload }
  }

  throw new Error(`HTTP request failed after retries for ${method} ${path}`)
}

async function createAuthSession(label: string): Promise<AuthSession> {
  const email = `${label}-${Date.now()}-${randomSuffix(6)}@example.com`
  const password = SESSION_PASSWORD

  const signUpResponse = await fetch(`${API_BASE_URL}/api/auth/sign-up/email`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      origin: TRUSTED_ORIGIN,
    },
    body: JSON.stringify({
      email,
      password,
      name: label,
    }),
  })

  const signUpPayload = await signUpResponse.json().catch(() => ({}))
  if (signUpResponse.status !== 200) {
    throw new Error(`Sign-up failed (${email}): ${JSON.stringify(signUpPayload)}`)
  }

  const cookie = cookieFromSetCookie(signUpResponse.headers.get('set-cookie'))
  const session = await requestJson<{ user: { id: string } }>('/api/auth/get-session', {
    cookie,
    raw: true,
    acceptStatuses: [200],
  })

  const userId = session.payload?.user?.id
  if (!userId) {
    throw new Error(`Could not resolve user id after sign-up (${email}).`)
  }

  return { email, password, userId, cookie }
}

function blockStep(stepKey: string, reason: string, evidence?: Record<string, unknown>): never {
  throw new StepExecutionError('blocked', `${stepKey}: ${reason}`, evidence)
}

async function getAgentToolNames(ctx: RunContext): Promise<Set<string>> {
  if (ctx.agentToolNames) return ctx.agentToolNames
  const response = await requestJson<{ success: true; data: Array<{ name: string }> }>(
    '/api/v1/agents/tools',
    {
      cookie: ctx.owner.cookie,
      acceptStatuses: [200],
    },
  )
  const tools = getApiData<Array<{ name: string }>>(response.payload)
  const names = new Set(tools.map((tool) => String(tool.name || '').trim()).filter(Boolean))
  ctx.agentToolNames = names
  return names
}

function hasAnyToolByPattern(toolNames: Set<string>, patterns: RegExp[]) {
  for (const name of Array.from(toolNames)) {
    for (const pattern of patterns) {
      if (pattern.test(name)) return true
    }
  }
  return false
}

function getApiData<T>(payload: unknown): T {
  const envelope = payload as { success: boolean; data: T }
  return envelope.data
}

function applyPositiveJitter(baseMs: number, jitterMs: number) {
  if (jitterMs <= 0) return baseMs
  const delta = Math.floor(Math.random() * (jitterMs + 1))
  return baseMs + delta
}

type SagaRunClock = {
  id: string
  mode: 'virtual' | 'realtime'
  status: 'idle' | 'running' | 'paused' | 'completed' | 'cancelled'
  currentTimeAt: string
  timezone: string
  autoAdvance: boolean
  metadata?: Record<string, unknown>
}

type SagaSchedulerJob = {
  id: string
  status: 'pending' | 'ready' | 'running' | 'completed' | 'failed' | 'cancelled' | 'expired'
  jobType: 'step_delay' | 'condition_wait' | 'message_delivery' | 'custom'
  dueAt: string
  stepKey?: string | null
}

async function getSagaRunClock(ctx: RunContext): Promise<SagaRunClock> {
  const response = await requestJson<{ success: true; data: SagaRunClock }>(
    `/api/v1/ooda/sagas/runs/${ctx.runId}/clock`,
    {
      cookie: ctx.owner.cookie,
      acceptStatuses: [200],
    },
  )
  return getApiData<SagaRunClock>(response.payload)
}

async function advanceSagaRunClock(
  ctx: RunContext,
  params: { byMs?: number; setToIso?: string; reason: string; touchStatus?: SagaRunClock['status'] },
): Promise<SagaRunClock> {
  const response = await requestJson<{ success: true; data: SagaRunClock }>(
    `/api/v1/ooda/sagas/runs/${ctx.runId}/clock/advance`,
    {
      method: 'POST',
      cookie: ctx.owner.cookie,
      body: {
        byMs: params.byMs,
        setToIso: params.setToIso,
        reason: params.reason,
        touchStatus: params.touchStatus,
      },
      acceptStatuses: [200],
    },
  )
  return getApiData<SagaRunClock>(response.payload)
}

async function createSagaSchedulerJob(
  ctx: RunContext,
  params: {
    stepKey: string
    jobType: SagaSchedulerJob['jobType']
    status?: SagaSchedulerJob['status']
    delayMs?: number
    dueAtIso?: string
    conditionKey?: string | null
    timeoutAtIso?: string | null
    pollEveryMs?: number | null
    metadata?: Record<string, unknown>
  },
): Promise<SagaSchedulerJob> {
  const response = await requestJson<{ success: true; data: SagaSchedulerJob }>(
    `/api/v1/ooda/sagas/runs/${ctx.runId}/scheduler/jobs`,
    {
      method: 'POST',
      cookie: ctx.owner.cookie,
      body: {
        ...params,
      },
      acceptStatuses: [201],
    },
  )
  return getApiData<SagaSchedulerJob>(response.payload)
}

async function updateSagaSchedulerJob(
  ctx: RunContext,
  jobId: string,
  patch: {
    status?: SagaSchedulerJob['status']
    startedAt?: string | null
    completedAt?: string | null
    lastEvaluatedAt?: string | null
    failureMessage?: string | null
    resultPayload?: Record<string, unknown>
    metadataPatch?: Record<string, unknown>
    bumpAttempt?: boolean
  },
) {
  await requestJson(`/api/v1/ooda/sagas/runs/${ctx.runId}/scheduler/jobs/${jobId}`, {
    method: 'PATCH',
    cookie: ctx.owner.cookie,
    body: patch,
    acceptStatuses: [200],
  })
}

async function evaluateDelayCondition(ctx: RunContext, conditionKey: string): Promise<boolean> {
  const key = conditionKey.trim()
  if (!key) return true
  if (key === 'always') return true

  if (key.startsWith('message_for:')) {
    const actorKey = key.slice('message_for:'.length).trim()
    if (!actorKey) return false
    const response = await requestJson<{ success: true; data: unknown[] }>(
      `/api/v1/ooda/sagas/runs/${ctx.runId}/messages?actorKey=${encodeURIComponent(actorKey)}`,
      {
        cookie: ctx.owner.cookie,
        acceptStatuses: [200],
      },
    )
    const rows = getApiData<unknown[]>(response.payload)
    return rows.length > 0
  }

  if (key.startsWith('step_done:')) {
    const stepKey = key.slice('step_done:'.length).trim()
    if (!stepKey) return false
    const detail = await getSagaRun(ctx.owner, ctx.runId)
    const step = detail.steps.find((row) => row.stepKey === stepKey)
    if (!step) return false
    return ['passed', 'failed', 'skipped', 'blocked'].includes(step.status)
  }

  throw new StepExecutionError(
    'blocked',
    `Unsupported delay condition key: ${key}`,
    { supported: ['always', 'message_for:<actorKey>', 'step_done:<stepKey>'] },
  )
}

async function postSagaRunActorMessage(
  ctx: RunContext,
  input: {
    stepKey: string
    toActorKey: string
    channel: 'email' | 'sms' | 'push' | 'in_app'
    subject?: string | null
    bodyText: string
    status?: 'queued' | 'sent' | 'delivered' | 'read' | 'failed' | 'cancelled'
    metadata?: Record<string, unknown>
  },
) {
  const response = await requestJson<{ success: true; data: { id: string } }>(
    `/api/v1/ooda/sagas/runs/${ctx.runId}/messages`,
    {
      method: 'POST',
      cookie: ctx.owner.cookie,
      body: {
        stepKey: input.stepKey,
        fromActorKey: 'biz_owner',
        toActorKey: input.toActorKey,
        channel: input.channel,
        subject: input.subject ?? null,
        bodyText: input.bodyText,
        status: input.status ?? 'delivered',
        metadata: input.metadata ?? {},
      },
      acceptStatuses: [201],
    },
  )
  return getApiData<{ id: string }>(response.payload)
}

async function executeStepDelay(ctx: RunContext, step: SagaRunStep) {
  const mode = step.delayMode ?? 'none'
  const jitter = Math.max(0, Number(step.delayJitterMs ?? 0))
  if (mode === 'none') return

  const nowIso = () => new Date().toISOString()
  const clock = await getSagaRunClock(ctx)

  if (mode === 'fixed') {
    const baseMs = Number(step.delayMs ?? 0)
    if (!Number.isFinite(baseMs) || baseMs <= 0) {
      throw new StepExecutionError('blocked', `Invalid fixed delay for step ${step.stepKey}.`, {
        delayMode: mode,
        delayMs: step.delayMs ?? null,
      })
    }
    const effectiveDelayMs = applyPositiveJitter(baseMs, jitter)
    const job = await createSagaSchedulerJob(ctx, {
      stepKey: step.stepKey,
      jobType: 'step_delay',
      delayMs: effectiveDelayMs,
      metadata: {
        mode: 'fixed',
        baseDelayMs: baseMs,
        jitterMs: jitter,
      },
    })
    await updateSagaSchedulerJob(ctx, job.id, {
      status: 'running',
      startedAt: nowIso(),
      bumpAttempt: true,
    })
    const advancedClock = await advanceSagaRunClock(ctx, {
      byMs: effectiveDelayMs,
      reason: `step_delay:${step.stepKey}`,
      touchStatus: 'running',
    })
    await updateSagaSchedulerJob(ctx, job.id, {
      status: 'completed',
      completedAt: nowIso(),
      lastEvaluatedAt: nowIso(),
      resultPayload: {
        effectiveDelayMs,
        fromTimeAt: clock.currentTimeAt,
        toTimeAt: advancedClock.currentTimeAt,
      },
    })
    return
  }

  if (mode === 'until_condition') {
    const conditionKey = String(step.delayConditionKey ?? '').trim()
    if (!conditionKey) {
      throw new StepExecutionError(
        'blocked',
        `Missing delayConditionKey for until_condition step ${step.stepKey}.`,
      )
    }
    const schedulerDefaults =
      clock.metadata && typeof clock.metadata === 'object'
        ? ((clock.metadata.scheduler as Record<string, unknown> | undefined) ?? {})
        : {}
    const timeoutDefault =
      typeof schedulerDefaults.defaultTimeoutMs === 'number' && schedulerDefaults.defaultTimeoutMs > 0
        ? Math.floor(schedulerDefaults.defaultTimeoutMs)
        : 30000
    const pollDefault =
      typeof schedulerDefaults.defaultPollMs === 'number' && schedulerDefaults.defaultPollMs > 0
        ? Math.floor(schedulerDefaults.defaultPollMs)
        : 1000
    const maxTicksDefault =
      typeof schedulerDefaults.maxTicksPerStep === 'number' && schedulerDefaults.maxTicksPerStep > 0
        ? Math.floor(schedulerDefaults.maxTicksPerStep)
        : 500

    const timeoutMs = Math.max(1000, Number(step.delayTimeoutMs ?? timeoutDefault))
    const pollMs = Math.max(250, Number(step.delayPollMs ?? pollDefault))
    const maxTicks = Math.max(1, Math.min(maxTicksDefault, Math.ceil(timeoutMs / pollMs)))
    const timeoutAtIso = new Date(new Date(clock.currentTimeAt).getTime() + timeoutMs).toISOString()

    const job = await createSagaSchedulerJob(ctx, {
      stepKey: step.stepKey,
      jobType: 'condition_wait',
      status: 'running',
      dueAtIso: clock.currentTimeAt,
      conditionKey,
      timeoutAtIso,
      pollEveryMs: pollMs,
      metadata: {
        mode: 'until_condition',
        timeoutMs,
        pollMs,
        jitterMs: jitter,
        maxTicks,
      },
    })

    let elapsedMs = 0
    let tickCount = 0
    while (elapsedMs <= timeoutMs && tickCount < maxTicks) {
      await updateSagaSchedulerJob(ctx, job.id, {
        status: 'running',
        startedAt: tickCount === 0 ? nowIso() : undefined,
        lastEvaluatedAt: nowIso(),
        bumpAttempt: true,
      })
      const conditionMet = await evaluateDelayCondition(ctx, conditionKey)
      if (conditionMet) {
        await updateSagaSchedulerJob(ctx, job.id, {
          status: 'completed',
          completedAt: nowIso(),
          lastEvaluatedAt: nowIso(),
          resultPayload: {
            conditionMet: true,
            conditionKey,
            elapsedMs,
            tickCount,
          },
        })
        return
      }

      const intervalMs = applyPositiveJitter(pollMs, jitter)
      await advanceSagaRunClock(ctx, {
        byMs: intervalMs,
        reason: `condition_wait:${step.stepKey}:${conditionKey}`,
        touchStatus: 'running',
      })
      elapsedMs += intervalMs
      tickCount += 1
    }

    await updateSagaSchedulerJob(ctx, job.id, {
      status: 'expired',
      completedAt: nowIso(),
      failureMessage: `Timed out waiting for condition: ${conditionKey}`,
      resultPayload: {
        conditionMet: false,
        conditionKey,
        elapsedMs,
        timeoutMs,
        pollMs,
        tickCount,
      },
    })

    throw new StepExecutionError(
      'failed',
      `Delay condition timed out for ${step.stepKey} (${conditionKey}).`,
      {
        conditionKey,
        timeoutMs,
        pollMs,
        mode: 'virtual_clock',
      },
    )
  }

  throw new StepExecutionError('blocked', `Unsupported delay mode: ${mode}`, {
    delayMode: mode,
  })
}

async function listSagaDefinitions(owner: AuthSession): Promise<SagaDefinition[]> {
  const fetchLimit = MAX_SAGAS > 0 ? Math.max(MAX_SAGAS + SAGA_OFFSET, 1) : 2000
  const query = `?sync=true&limit=${fetchLimit}`
  const response = await requestJson<{ success: true; data: SagaDefinition[] }>(
    `/api/v1/ooda/sagas/specs${query}`,
    { cookie: owner.cookie, acceptStatuses: [200] },
  )
  const rows = getApiData<SagaDefinition[]>(response.payload)
  const activeRows = rows.filter((row) => row.status === 'active')
  return activeRows.slice(SAGA_OFFSET)
}

async function createSagaRun(owner: AuthSession, sagaKey: string) {
  const response = await requestJson<{ success: true; data: SagaRunDetail }>('/api/v1/ooda/sagas/runs', {
    method: 'POST',
    cookie: owner.cookie,
    body: {
      sagaKey,
      mode: process.env.SAGA_MODE === 'live' ? 'live' : 'dry_run',
      runnerLabel: SAGA_FAST_MODE ? 'codex-rerun-fast' : 'codex-rerun-all',
      runContext: {
        createdBy: 'apps/api/src/scripts/rerun-sagas.ts',
        fastMode: SAGA_FAST_MODE,
      },
    },
    acceptStatuses: [201],
  })
  return getApiData<SagaRunDetail>(response.payload)
}

async function getSagaRun(owner: AuthSession, runId: string) {
  const response = await requestJson<{ success: true; data: SagaRunDetail }>(
    `/api/v1/ooda/sagas/runs/${runId}`,
    { cookie: owner.cookie, acceptStatuses: [200] },
  )
  return getApiData<SagaRunDetail>(response.payload)
}

async function reportStep(
  ctx: RunContext,
  stepKey: string,
  status: 'passed' | 'failed' | 'blocked' | 'skipped',
  resultPayload: StepResultPayload,
  failureMessage?: string,
  assertionSummary?: Record<string, unknown>,
) {
  const startedAt = nowIso()
  const endedAt = nowIso()

  /**
   * We always transition via `in_progress` first so step state progression
   * matches production-like lifecycle semantics.
   */
  if (SAGA_STEP_TRANSITION_IN_PROGRESS) {
    try {
      await requestJson(`/api/v1/ooda/sagas/runs/${ctx.runId}/steps/${stepKey}/result`, {
        method: 'POST',
        cookie: ctx.owner.cookie,
        body: {
          status: 'in_progress',
          startedAt,
          resultPayload: {
            note: `Started ${stepKey}`,
          },
          assertionSummary: {
            status: 'in_progress',
          },
        },
        acceptStatuses: [200],
      })
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error)
      const staleTransition =
        message.includes('Invalid step status transition') &&
        message.includes('passed -> in_progress')
      if (!staleTransition) {
        throw error
      }
    }
  }

  await requestJson(`/api/v1/ooda/sagas/runs/${ctx.runId}/steps/${stepKey}/result`, {
    method: 'POST',
    cookie: ctx.owner.cookie,
    body: {
      status,
      startedAt,
      endedAt,
      failureMessage: failureMessage ?? null,
      resultPayload,
      assertionSummary: {
        status,
        hasFailure: Boolean(failureMessage),
        assertionsPassed: status === 'passed' ? 1 : 0,
        ...(assertionSummary ?? {}),
      },
    },
    acceptStatuses: [200],
  })
}

function toneFromStatus(status: string) {
  if (status === 'passed') return 'success'
  if (status === 'failed' || status === 'blocked') return 'error'
  if (status === 'skipped') return 'warning'
  return 'info'
}

function buildSnapshotBlocks(
  stepKey: string,
  result: StepResultPayload,
  status: 'passed' | 'failed' | 'blocked' | 'skipped',
): SnapshotBlock[] {
  const blocks: SnapshotBlock[] = [
    {
      type: 'alert',
      title: `${toTitleCase(stepKey)} ${status === 'passed' ? 'completed' : status}`,
      message: result.note,
      tone: toneFromStatus(status),
    },
  ]

  const evidence = isRecord(result.evidence) ? result.evidence : null
  if (!evidence) return blocks

  if (stepKey === 'owner-sign-up' || stepKey === 'customer-sign-up') {
    const idLabel = stepKey === 'owner-sign-up' ? 'Owner user id' : 'Customer user id'
    blocks.push({
      type: 'form',
      title: 'Account session state',
      fields: [
        { label: idLabel, value: asString(evidence.ownerUserId ?? evidence.customerUserId ?? 'n/a') },
        { label: 'Email', value: asString(evidence.ownerEmail ?? evidence.email ?? 'n/a') },
        { label: 'Session', value: status === 'passed' ? 'Active' : 'Unavailable', state: status === 'passed' ? 'success' : 'error' },
      ],
      submitLabel: status === 'passed' ? 'Authenticated' : 'Failed',
    })
  }

  if (stepKey === 'owner-create-biz') {
    blocks.push({
      type: 'key_value',
      title: 'Business profile',
      items: [
        { label: 'Name', value: asString(evidence.name ?? 'n/a') },
        { label: 'Slug', value: asString(evidence.slug ?? 'n/a') },
        { label: 'Timezone', value: asString(evidence.timezone ?? 'UTC') },
        { label: 'Currency', value: asString(evidence.currency ?? 'USD') },
      ],
    })
    blocks.push({
      type: 'actions',
      title: 'Visible actions',
      items: [
        { label: 'Edit business settings', kind: 'primary', enabled: true },
        { label: 'Add location', kind: 'secondary', enabled: true },
      ],
    })
  }

  if (stepKey === 'customer-book-primary' || stepKey === 'customer-two-concurrent') {
    blocks.push({
      type: 'key_value',
      title: 'Booking confirmation',
      items: [
        { label: 'Booking id', value: asString(evidence.id ?? 'n/a') },
        { label: 'Status', value: asString(evidence.status ?? 'n/a') },
        { label: 'Starts at', value: asString(evidence.confirmedStartAt ?? evidence.requestedStartAt ?? 'n/a') },
        { label: 'Total', value: asString(evidence.totalMinor ?? 'n/a') },
      ],
    })
    blocks.push({
      type: 'actions',
      title: 'Visible actions',
      items: [
        { label: 'Download receipt', kind: 'secondary', enabled: true },
        { label: 'Reschedule', kind: 'secondary', enabled: true },
        { label: 'Cancel booking', kind: 'danger', enabled: true },
      ],
    })
  }

  const metrics = Object.entries(evidence).filter(([key]) => /count$|minor$|total$/i.test(key))
  if (metrics.length > 0) {
    blocks.push({
      type: 'stats',
      title: 'What user sees at a glance',
      items: metrics.slice(0, 8).map(([key, value]) => ({
        label: toTitleCase(key),
        value: asString(value),
      })),
    })
  }

  if (stepKey === 'owner-calendar-review') {
    const bookings = Array.isArray(evidence.bookingPreview)
      ? evidence.bookingPreview
      : Array.isArray(evidence.events)
        ? evidence.events
        : []
    const events = bookings
      .slice(0, 10)
      .map((row) => {
        if (!isRecord(row)) return null
        const start = asString(row.confirmedStartAt ?? row.requestedStartAt ?? row.startAt ?? 'unknown')
        const end = asString(row.confirmedEndAt ?? row.requestedEndAt ?? row.endAt ?? 'unknown')
        const label = asString(row.offerTitle ?? row.title ?? row.id ?? 'Booking')
        return {
          timeRange: `${start} → ${end}`,
          title: label,
          status: 'booked',
          detail: asString(row.status ?? ''),
        }
      })
      .filter(Boolean)

    blocks.push({
      type: 'calendar',
      title: 'Calendar snapshot',
      timezone: asString(evidence.timezone ?? 'UTC'),
      rangeLabel: asString(evidence.rangeLabel ?? 'Upcoming'),
      events,
    })
    blocks.push({
      type: 'actions',
      title: 'Visible actions',
      items: [
        { label: 'Filter by resource', kind: 'secondary', enabled: true },
        { label: 'Create manual block', kind: 'secondary', enabled: true },
        { label: 'Open booking detail', kind: 'primary', enabled: events.length > 0 },
      ],
    })
    return blocks
  }

  const rowArrays = Object.entries(evidence).find(
    ([, value]) =>
      Array.isArray(value) && value.length > 0 && value.every((entry) => isRecord(entry)),
  )
  if (rowArrays) {
    const [key, value] = rowArrays
    const rows = value as Array<Record<string, unknown>>
    const columns = Array.from(
      rows.reduce((acc, row) => {
        Object.keys(row).forEach((col) => acc.add(col))
        return acc
      }, new Set<string>()),
    ).slice(0, 8)
    blocks.push({
      type: 'table',
      title: toTitleCase(key),
      columns,
      rows: rows.slice(0, 20).map((row) => columns.map((col) => row[col] ?? null)),
    })
  } else {
    const scalarItems = Object.entries(evidence)
      .filter(([, value]) => value === null || typeof value !== 'object')
      .slice(0, 16)
      .map(([key, value]) => ({ label: toTitleCase(key), value: asString(value) }))

    if (scalarItems.length > 0) {
      blocks.push({
        type: 'key_value',
        title: 'Screen details',
        items: scalarItems,
      })
    } else {
      blocks.push({
        type: 'raw_json',
        title: 'Evidence payload',
        data: evidence,
      })
    }
  }

  return blocks
}

async function attachSnapshot(
  ctx: RunContext,
  stepKey: string,
  stepTitle: string,
  status: 'passed' | 'failed' | 'blocked' | 'skipped',
  result: StepResultPayload,
  rawData?: Record<string, unknown>,
) {
  const snapshotBody = {
    stepKey,
    screenKey: `${stepKey}-${Date.now()}`,
    title: `${stepTitle} Snapshot`,
    status,
    route: `/sagas/${ctx.runId}/${stepKey}`,
    format: 'json' as const,
    view: {
      title: stepTitle,
      subtitle: result.note,
      blocks: buildSnapshotBlocks(stepKey, result, status),
    },
    rawData,
  }

  try {
    await requestJson(`/api/v1/ooda/sagas/runs/${ctx.runId}/snapshots`, {
      method: 'POST',
      cookie: ctx.owner.cookie,
      body: snapshotBody,
      acceptStatuses: [201],
    })
  } catch {
    /**
     * Snapshot visuals are evidence helpers, not the source of truth.
     * If a newer visual block shape drifts from the validator, we still attach
     * a legacy snapshot so the saga result stays readable instead of failing on
     * presentation-only payload shape.
     */
    await requestJson(`/api/v1/ooda/sagas/runs/${ctx.runId}/snapshots`, {
      method: 'POST',
      cookie: ctx.owner.cookie,
      body: {
        stepKey,
        screenKey: `${stepKey}-legacy-${Date.now()}`,
        title: `${stepTitle} Snapshot`,
        status,
        route: `/sagas/${ctx.runId}/${stepKey}`,
        format: 'json',
        data: {
          note: result.note,
          status,
          evidence: result.evidence ?? {},
          visibleActions: ['Inspect detail', 'Review evidence'],
        },
        rawData,
      },
      acceptStatuses: [201],
    })
  }
}

async function attachApiTrace(ctx: RunContext, stepKey: string, stepTitle: string, apiCalls: ApiTraceEntry[]) {
  await requestJson(`/api/v1/ooda/sagas/runs/${ctx.runId}/traces`, {
    method: 'POST',
    cookie: ctx.owner.cookie,
    body: {
      stepKey,
      title: `${stepTitle} API Trace`,
      trace: {
        stepKey,
        callCount: apiCalls.length,
        calls: apiCalls,
      },
      metadata: {
        source: 'rerun-sagas.ts',
      },
    },
    acceptStatuses: [201],
  })
}

async function createBiz(ctx: RunContext) {
  const slug = `${toSlug(ctx.sagaKey, 60)}-${randomSuffix(8)}`
  const response = await requestJson<{ success: true; data: { id: string; slug: string } }>(
    '/api/v1/bizes',
    {
      method: 'POST',
      cookie: ctx.owner.cookie,
      body: {
        name: `Saga ${ctx.sagaKey}`,
        slug,
        type: 'small_business',
        timezone: 'UTC',
        currency: 'USD',
      },
      acceptStatuses: [201],
    },
  )
  const biz = getApiData<{ id: string; slug: string }>(response.payload)
  ctx.bizId = biz.id
  return biz
}

