async function ensureValidationSellableId(ctx: RunContext) {
  if (!ctx.bizId) throw new Error('bizId required before sellable fixture.')
  if (!ctx.offerId) await createOffer(ctx)
  if (!ctx.offerVersionId) await createOfferVersion(ctx)
  if (!ctx.validationSellableId) {
    const sellableRows = getApiData<Array<{ id: string }>>(
      (
        await requestJson(`/api/v1/bizes/${ctx.bizId}/sellables?offerVersionId=${ctx.offerVersionId}`, {
          cookie: ctx.owner.cookie,
          acceptStatuses: [200],
        })
      ).payload,
    )
    const sellable = sellableRows[0]
    if (!sellable) {
      throw new Error(`Could not resolve canonical sellable for offerVersionId=${ctx.offerVersionId}.`)
    }
    ctx.validationSellableId = sellable.id
  }
  return ctx.validationSellableId
}

