    if (retried.delivery.attemptCount < 1 || retried.backoffMinutes < 1) {
      blockStep(step.stepKey, 'Manual retry did not produce a new attempt with computed backoff.', retried)
    }
    return { note: 'Validated webhook retry flow computes a concrete backoff window and requeues the delivery.', evidence: retried }
